import React from "react";

class About extends React.Component {
  constructor() {
    super();
    this.state = {
      skills: [
        {
          id: "Flutter_skill",
          content: "Flutter",
          porcentage: "60%",
          value: "60",
        },
        {
          id: "C#_skill",
          content: "C#",
          porcentage: "80%",
          value: "80",
        },
        {
          id: "ReactJS_skill",
          content: "ReactJS",
          porcentage: "60%",
          value: "60",
        },
        {
          id: "ReactNative_skill",
          content: "React-Native",
          porcentage: "60%",
          value: "60",
        },
        {
          id: "Kotlin_skill",
          content: "Kotlin",
          porcentage: "45%",
          value: "45",
        },
        { id: "HTML5_skill", content: "HTML5", porcentage: "55%", value: "55" },
        { id: "CSS_skill", content: "CSS", porcentage: "50%", value: "50" },
        {
          id: "JavaScript_skill",
          content: "JavaScript",
          porcentage: "60%",
          value: "60",
        },
      ],
      about_me: [
        {
          id: "first-p-about",
          content:
            "My name is Vilius and I am a third-year ICT & Software Engineer student at Fontys Univerity of Applied Sciences. My studies have provided me with a strong foundation in the IT industry including the knowledge about Software development. In my spare time, I like to spend my time playing basketball or just hanging out with my friends.",
        },
      ],
    };
  }

  render() {
    return (
      <section id="about" className="about-mf sect-pt4 route">
        <div className="container">
          <div className="row">
            <div className="col-sm-12">
              <div className="box-shadow-full">
                <div className="row">
                  <div className="col-md-6">
                    <div className="row">
                      <div
                        className="col-sm-6 col-md-5"
                        style={{ margin: "0 auto" }}
                      >
                        <div
                          className="about-img"
                          style={{ textAlign: "center" }}
                        >
                          <img
                            className="img-fluid rounded b-shadow-a"
                            alt=""
                          />
                        </div>
                      </div>
                    </div>
                    <div className="skill-mf">
                      {this.state.skills.map((skill) => {
                        return (
                          <React.Fragment key={skill.id}>
                            <span>{skill.content}</span>{" "}
                            <span className="pull-right">
                              {skill.porcentage}
                            </span>
                            <div className="progress">
                              <div
                                className="progress-bar"
                                role="progressbar"
                                style={{ width: skill.porcentage }}
                                aria-valuenow={skill.value}
                                aria-valuemin="0"
                                aria-valuemax="100"
                              ></div>
                            </div>
                          </React.Fragment>
                        );
                      })}
                    </div>
                  </div>
                  <div className="col-md-6">
                    <div className="about-me pt-4 pt-md-0">
                      <div className="title-box-2">
                        <h5 className="title-left">About Me</h5>
                      </div>
                      {this.state.about_me.map((content) => {
                        return (
                          <p className="lead" key={content.id}>
                            {content.content}
                          </p>
                        );
                      })}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
    );
  }
}

export default About;
